Experten-Analyse (gemini-pro-latest):
Hier ist die tiefgründige und präzise Lösung für dein Vorhaben. 

### Architektur & Strategie

1. **USB-Exklusivität:** Um den binären ESP3-Datenstrom nicht zu korrumpieren, deaktivieren wir das ESP-Logging zur Laufzeit komplett und nutzen den `usb_serial_jtag` Treiber exklusiv für In/Out.
2. **ESP3 Parser:** Eine State-Machine liest den Stream asynchron aus dem USB-Puffer. Sie ist fehlertolerant (falsche CRCs verwerfen das Paket und suchen nach dem nächsten Sync-Byte 0x55).
3. **LBT & Subtelegramme:** Vor dem Senden liest der ESP32 über SPI das RSSI-Register des CC1101 aus. Ist der Kanal belegt, wird kurz gewartet. Danach werden 3 Subtelegramme mit einem Pseudo-Zufalls-Delay (~10-20ms) gesendet.
4. **Halbduplex-Sicherheit:** Da der CC1101 nicht gleichzeitig senden und empfangen kann, maskieren wir RX-Interrupts während der TX-Phase.

---

### 1. ESP3 Protokoll Parser (`esp3_proto.h` & `esp3_proto.c`)

**esp3_proto.h**
```c
#pragma once
#include <stdint.h>
#include <stdbool.h>

#define ESP3_SYNC_BYTE 0x55

// ESP3 Packet Types
#define ESP3_TYPE_RADIO_ERP1 0x01
#define ESP3_TYPE_RESPONSE   0x02

// Response Codes
#define RET_OK 0x00

typedef struct {
    uint16_t data_len;
    uint8_t opt_len;
    uint8_t packet_type;
    uint8_t *data;
    uint8_t *opt_data;
} esp3_packet_t;

// API
void esp3_init(void);
void esp3_process_byte(uint8_t byte);
void esp3_send_packet(uint8_t type, const uint8_t *data, uint16_t data_len, const uint8_t *opt, uint8_t opt_len);
void esp3_send_response(uint8_t ret_code);
```

**esp3_proto.c**
```c
#include "esp3_proto.h"
#include "radio_hal.h"
#include "driver/usb_serial_jtag.h"
#include <stdlib.h>
#include <string.h>

typedef enum {
    STATE_SYNC, STATE_HEADER, STATE_CRC8H, STATE_DATA, STATE_CRC8D
} esp3_state_t;

static esp3_state_t rx_state = STATE_SYNC;
static uint8_t header_buf[4];
static uint8_t header_idx = 0;
static uint8_t *payload_buf = NULL;
static uint16_t payload_idx = 0;
static esp3_packet_t current_packet;

// EnOcean CRC8 (Polynomial 0x07)
static uint8_t crc8_calc(uint8_t data, uint8_t crc) {
    crc ^= data;
    for (int i = 0; i < 8; i++) {
        if (crc & 0x80) crc = (crc << 1) ^ 0x07;
        else crc <<= 1;
    }
    return crc;
}

static uint8_t calc_buffer_crc(const uint8_t *buf, uint16_t len) {
    uint8_t crc = 0;
    for (uint16_t i = 0; i < len; i++) {
        crc = crc8_calc(buf[i], crc);
    }
    return crc;
}

void esp3_init(void) {
    rx_state = STATE_SYNC;
}

void esp3_send_packet(uint8_t type, const uint8_t *data, uint16_t data_len, const uint8_t *opt, uint8_t opt_len) {
    uint8_t header[4] = { (uint8_t)(data_len >> 8), (uint8_t)(data_len & 0xFF), opt_len, type };
    uint8_t crc8h = calc_buffer_crc(header, 4);

    uint8_t crc8d = 0;
    if (data_len > 0) crc8d = calc_buffer_crc(data, data_len);
    if (opt_len > 0) {
        // Continue CRC calculation with option data
        for(int i=0; i<opt_len; i++) crc8d = crc8_calc(opt[i], crc8d);
    }

    uint8_t sync = ESP3_SYNC_BYTE;

    // Direct write to USB-JTAG
    usb_serial_jtag_write_bytes(&sync, 1, portMAX_DELAY);
    usb_serial_jtag_write_bytes(header, 4, portMAX_DELAY);
    usb_serial_jtag_write_bytes(&crc8h, 1, portMAX_DELAY);
    if (data_len > 0) usb_serial_jtag_write_bytes(data, data_len, portMAX_DELAY);
    if (opt_len > 0) usb_serial_jtag_write_bytes(opt, opt_len, portMAX_DELAY);
    usb_serial_jtag_write_bytes(&crc8d, 1, portMAX_DELAY);

    // Flush to host immediately
    usb_serial_jtag_ll_txflush(); 
}

void esp3_send_response(uint8_t ret_code) {
    esp3_send_packet(ESP3_TYPE_RESPONSE, &ret_code, 1, NULL, 0);
}

void esp3_process_byte(uint8_t byte) {
    switch (rx_state) {
        case STATE_SYNC:
            if (byte == ESP3_SYNC_BYTE) {
                header_idx = 0;
                rx_state = STATE_HEADER;
            }
            break;

        case STATE_HEADER:
            header_buf[header_idx++] = byte;
            if (header_idx == 4) rx_state = STATE_CRC8H;
            break;

        case STATE_CRC8H:
            if (byte == calc_buffer_crc(header_buf, 4)) {
                current_packet.data_len = (header_buf[0] << 8) | header_buf[1];
                current_packet.opt_len = header_buf[2];
                current_packet.packet_type = header_buf[3];

                uint16_t total_len = current_packet.data_len + current_packet.opt_len;
                if (total_len > 0) {
                    payload_buf = malloc(total_len);
                    if (!payload_buf) { rx_state = STATE_SYNC; return; } // OOM Guard
                    payload_idx = 0;
                    rx_state = STATE_DATA;
                } else {
                    rx_state = STATE_CRC8D; // No data, jump to CRC
                }
            } else {
                rx_state = STATE_SYNC; // CRC Header failed
            }
            break;

        case STATE_DATA:
            payload_buf[payload_idx++] = byte;
            if (payload_idx == (current_packet.data_len + current_packet.opt_len)) {
                rx_state = STATE_CRC8D;
            }
            break;

        case STATE_CRC8D:
            if (byte == calc_buffer_crc(payload_buf, current_packet.data_len + current_packet.opt_len)) {
                // Valid Packet Received
                current_packet.data = payload_buf;
                current_packet.opt_data = payload_buf + current_packet.data_len;

                // TCM515 Emulation: If ERP1 arrives from Host, transmit it!
                if (current_packet.packet_type == ESP3_TYPE_RADIO_ERP1) {
                    radio_transmit(current_packet.data, current_packet.data_len);
                    esp3_send_response(RET_OK);
                }
            }

            // Cleanup
            if (payload_buf) free(payload_buf);
            payload_buf = NULL;
            rx_state = STATE_SYNC;
            break;
    }
}
```

---

### 2. CC1101 Radio HAL mit LBT & RX-ISR (`radio_hal.h` & `radio_hal.c`)

Hier ist die Implementierung von Listen Before Talk. Anstatt ein GPIO-Pin (GDO2) zu verwenden, ist das Abfragen des `RSSI` Registers über SPI robuster und blockiert keine Hardware-Ressourcen des C6.

**radio_hal.h**
```c
#pragma once
#include <stdint.h>
#include <stdbool.h>
#include "freertos/FreeRTOS.h"
#include "freertos/semphr.h"

// Externe Abhängigkeit zu deinem bestehenden SPI-Code
extern uint8_t cc1101_read_reg(uint8_t reg);
extern void cc1101_write_fifo(const uint8_t *data, uint8_t len);
extern void cc1101_read_fifo(uint8_t *data, uint8_t len);
extern void cc1101_strobe(uint8_t cmd);

#define CC1101_SIDLE 0x36
#define CC1101_SRX   0x34
#define CC1101_STX   0x35
#define CC1101_SFLUSHTX 0x3B
#define CC1101_SFLUSHRX 0x3A

void radio_init(void);
void radio_transmit(const uint8_t *data, uint8_t len);
extern SemaphoreHandle_t rf_rx_semaphore;
```

**radio_hal.c**
```c
#include "radio_hal.h"
#include "esp_random.h"
#include "esp_timer.h"
#include "driver/gpio.h"
#include "freertos/task.h"

#define GDO0_PIN 4 // Passe dies an dein Hardware-Setup an
#define RSSI_THRESHOLD 75 // Entspricht ca. -85dBm (je nach Konfiguration)

SemaphoreHandle_t rf_rx_semaphore = NULL;
volatile bool is_transmitting = false;

// ISR Handler für CC1101 GDO0 (RX Packet Received / CRC OK)
static void IRAM_ATTR cc1101_gdo0_isr(void* arg) {
    if (!is_transmitting && rf_rx_semaphore != NULL) {
        BaseType_t xHigherPriorityTaskWoken = pdFALSE;
        xSemaphoreGiveFromISR(rf_rx_semaphore, &xHigherPriorityTaskWoken);
        if (xHigherPriorityTaskWoken) portYIELD_FROM_ISR();
    }
}

void radio_init(void) {
    rf_rx_semaphore = xSemaphoreCreateBinary();

    // ISR Setup (Angenommen GDO0 ist konfiguriert auf RX_CRC_OK (0x07))
    gpio_config_t io_conf = {
        .intr_type = GPIO_INTR_POSEDGE,
        .pin_bit_mask = (1ULL << GDO0_PIN),
        .mode = GPIO_MODE_INPUT,
        .pull_down_en = 0,
        .pull_up_en = 0
    };
    gpio_config(&io_conf);
    gpio_install_isr_service(0);
    gpio_isr_handler_add(GDO0_PIN, cc1101_gdo0_isr, NULL);

    // Stelle sicher, dass RX aktiv ist
    cc1101_strobe(CC1101_SRX);
}

static bool check_lbt(void) {
    // Lese RSSI Register (Status Register 0x34)
    uint8_t rssi_dec = cc1101_read_reg(0x34 | 0xC0); // 0xC0 für Status-Register Read
    // Einfache Schwellwertprüfung. Komplexere Logik nutzt 2er-Komplement, 
    // aber für relative LBT-Check reicht oft der rohe Wert je nach Konfig.
    if (rssi_dec >= RSSI_THRESHOLD) return false; // Kanal belegt
    return true; // Kanal frei
}

void radio_transmit(const uint8_t *data, uint8_t len) {
    is_transmitting = true;

    // LBT Loop (Max 5 Versuche)
    for(int i=0; i<5; i++) {
        if(check_lbt()) break;
        vTaskDelay(pdMS_TO_TICKS(2 + (esp_random() % 5))); // 2-7ms Backoff
    }

    // Subtelegramm Loop (3x Senden)
    for(int sub = 0; sub < 3; sub++) {
        cc1101_strobe(CC1101_SIDLE);
        cc1101_strobe(CC1101_SFLUSHTX);

        cc1101_write_fifo(data, len);
        cc1101_strobe(CC1101_STX);

        // Warte bis TX abgeschlossen (Abfrage MARCSTATE, 0x01 = IDLE)
        // Alternativ kann man hier GDO2 prüfen
        int timeout = 50; 
        while((cc1101_read_reg(0x35 | 0xC0) & 0x1F) != 0x01 && timeout > 0) {
            vTaskDelay(pdMS_TO_TICKS(1));
            timeout--;
        }

        // Pseudo-Zufalls-Delay (~10ms + 0-15ms Jitter)
        if (sub < 2) {
            uint32_t delay_ms = 10 + (esp_random() % 16);
            vTaskDelay(pdMS_TO_TICKS(delay_ms));
        }
    }

    // Zurück in RX
    cc1101_strobe(CC1101_SFLUSHRX);
    cc1101_strobe(CC1101_SRX);
    is_transmitting = false;
}
```

---

### 3. Hauptprogramm (`main.c`)

Hier deaktivieren wir das Logging auf der USB-Schnittstelle und implementieren die Tasks für USB-RX und RF-RX.

**main.c**
```c
#include <stdio.h>
#include "freertos/FreeRTOS.h"
#include "freertos/task.h"
#include "driver/usb_serial_jtag.h"
#include "esp_log.h"
#include "esp3_proto.h"
#include "radio_hal.h"

// USB Task zum Lesen des Host-ESP3-Streams
void usb_rx_task(void *pvParameters) {
    uint8_t rx_buf[64];
    while (1) {
        int bytes_read = usb_serial_jtag_read_bytes(rx_buf, sizeof(rx_buf), portMAX_DELAY);
        if (bytes_read > 0) {
            for (int i = 0; i < bytes_read; i++) {
                esp3_process_byte(rx_buf[i]);
            }
        }
    }
}

// RF Task, ausgelöst durch CC1101 ISR
void rf_rx_task(void *pvParameters) {
    uint8_t fifo_buf[64];

    while (1) {
        if (xSemaphoreTake(rf_rx_semaphore, portMAX_DELAY) == pdTRUE) {
            // Lese RXBYTES Register (0x3B)
            uint8_t rx_bytes = cc1101_read_reg(0x3B | 0xC0) & 0x7F;

            if (rx_bytes > 0 && rx_bytes <= sizeof(fifo_buf)) {
                cc1101_read_fifo(fifo_buf, rx_bytes);

                // Option Data Dummy für EnOcean (SubTelNum, DBm, etc.)
                // Hier stark vereinfacht: 1 Byte Opt-Data (RSSI)
                uint8_t opt_data[1] = { cc1101_read_reg(0x34 | 0xC0) };

                // Packe und Sende als ESP3 via USB
                esp3_send_packet(ESP3_TYPE_RADIO_ERP1, fifo_buf, rx_bytes, opt_data, 1);
            }

            // CC1101 sauber machen für nächsten Empfang
            cc1101_strobe(CC1101_SIDLE);
            cc1101_strobe(CC1101_SFLUSHRX);
            cc1101_strobe(CC1101_SRX);
        }
    }
}

void app_main(void) {
    // 1. ESP-Logging komplett ausschalten (Exklusivität für ESP3)
    esp_log_level_set("*", ESP_LOG_NONE);

    // Standard IO umbiegen, damit printf nicht stört
    stdout = NULL;
    stderr = NULL;

    // 2. Initialisiere USB Serial JTAG Treiber
    usb_serial_jtag_driver_config_t usb_config = {
        .tx_buffer_size = 256,
        .rx_buffer_size = 256,
    };
    usb_serial_jtag_driver_install(&usb_config);

    // 3. System-Initialisierungen
    esp3_init();

    // (Hier würdest du deinen bestehenden CC1101 SPI Init aufrufen)
    // cc1101_spi_init();

    radio_init();

    // 4. Tasks starten
    xTaskCreate(usb_rx_task, "usb_rx", 4096, NULL, 5, NULL);
    xTaskCreate(rf_rx_task, "rf_rx", 4096, NULL, 6, NULL); // RF etwas höhere Prio
}
```

### Zusammenfassung der Architektur-Highlights:
* **`esp_log_level_set("*", ESP_LOG_NONE);`** und das Nullen von `stdout` verhindert, dass ESP-IDF Boot-Logs oder Kernel-Warnungen als ungültige ESP3-Daten beim Host (z.B. FHEM, HomeAssistant) ankommen.
* Die `esp3_send_packet` Funktion schreibt via `usb_serial_jtag_write_bytes` und erzwingt einen Flush (`usb_serial_jtag_ll_txflush();`). Letzteres ist beim C6 essenziell für latenzfreie Kommunikation.
* Der Halbduplex-Lock `is_transmitting` schützt davor, dass der ESP32 während der 3 pseudo-randomisierten Sendevorgänge aus dem Tritt kommt, falls das GDO0-Pin des CC1101 auf `TX_SYNC` oder andere TX-Events triggert.

args.content:
#ifndef RADIO_HAL_H
#define RADIO_HAL_H

#include <stdint.h>
#include <stdbool.h>
#include "freertos/FreeRTOS.h"
#include "freertos/semphr.h"

// --- PIN DEFINITIONS (ESP32-C6) ---
#define PIN_GDO0   2
#define PIN_GDO2   3
#define PIN_LED    8
#define PIN_SWITCH 9
#define PIN_SS     18
#define PIN_SCK    19
#define PIN_MISO   20
#define PIN_MOSI   21

#ifdef __cplusplus
extern "C" {
#endif

void radio_hal_init(void);
void radio_transmit(const uint8_t *data, uint8_t len);

// SPI Primitives
void cc1101_strobe(uint8_t cmd);
void cc1101_write_reg(uint8_t addr, uint8_t value);
uint8_t cc1101_read_reg(uint8_t addr);
uint8_t cc1101_read_status(uint8_t addr);

// Data Primitives
void cc1101_write_burst(uint8_t addr, const uint8_t *data, uint8_t len);
void cc1101_read_burst(uint8_t addr, uint8_t *data, uint8_t len);

extern SemaphoreHandle_t rf_rx_semaphore;

#ifdef __cplusplus
}
#endif

#endif // RADIO_HAL_H

#include "radio_hal.h"
#include "cc1101_regs.h"
#include "driver/spi_master.h"
#include "driver/gpio.h"
#include "esp_log.h"
#include "esp_random.h"
#include "freertos/FreeRTOS.h"
#include "freertos/task.h"

static const char *TAG = "RADIO_HAL";
static spi_device_handle_t spi_handle;
SemaphoreHandle_t rf_rx_semaphore = NULL;
volatile bool is_transmitting = false;

static void IRAM_ATTR cc1101_gdo0_isr(void* arg) {
    if (!is_transmitting && rf_rx_semaphore != NULL) {
        BaseType_t xHigherPriorityTaskWoken = pdFALSE;
        xSemaphoreGiveFromISR(rf_rx_semaphore, &xHigherPriorityTaskWoken);
        if (xHigherPriorityTaskWoken) portYIELD_FROM_ISR();
    }
}

static void spi_init(void) {
    spi_bus_config_t buscfg = {
        .miso_io_num = PIN_MISO,
        .mosi_io_num = PIN_MOSI,
        .sclk_io_num = PIN_SCK,
        .quadwp_io_num = -1,
        .quadhd_io_num = -1,
        .max_transfer_sz = 64
    };

    spi_device_interface_config_t devcfg = {
        .clock_speed_hz = 5000000,
        .mode = 0,
        .spics_io_num = PIN_SS,
        .queue_size = 3,
        .flags = 0
    };

    ESP_ERROR_CHECK(spi_bus_initialize(SPI2_HOST, &buscfg, SPI_DMA_DISABLED));
    ESP_ERROR_CHECK(spi_bus_add_device(SPI2_HOST, &devcfg, &spi_handle));
}

static void gpio_init(void) {
    gpio_config_t io_out = {
        .pin_bit_mask = (1ULL << PIN_LED),
        .mode = GPIO_MODE_OUTPUT,
        .pull_up_en = 1,
        .pull_down_en = 0,
        .intr_type = GPIO_INTR_DISABLE
    };
    gpio_config(&io_out);
    gpio_set_level(PIN_LED, 1);

    gpio_config_t io_in = {
        .pin_bit_mask = (1ULL << PIN_GDO0) | (1ULL << PIN_GDO2) | (1ULL << PIN_SWITCH),
        .mode = GPIO_MODE_INPUT,
        .pull_up_en = 1,
        .pull_down_en = 0,
        .intr_type = GPIO_INTR_NEGEDGE // For GDO0
    };
    gpio_config(&io_in);
}

void cc1101_strobe(uint8_t cmd) {
    spi_transaction_t t = {
        .length = 8,
        .tx_data = {cmd},
        .flags = SPI_TRANS_USE_TXDATA
    };
    spi_device_polling_transmit(spi_handle, &t);
}

void cc1101_write_reg(uint8_t addr, uint8_t value) {
    uint8_t tx_data[2] = { addr, value };
    spi_transaction_t t = {
        .length = 16,
        .tx_buffer = tx_data
    };
    spi_device_polling_transmit(spi_handle, &t);
}

uint8_t cc1101_read_reg(uint8_t addr) {
    uint8_t tx_data[2] = { (uint8_t)(addr | 0x80), 0x00 };
    uint8_t rx_data[2] = { 0 };
    spi_transaction_t t = {
        .length = 16,
        .tx_buffer = tx_data,
        .rx_buffer = rx_data
    };
    spi_device_polling_transmit(spi_handle, &t);
    return rx_data[1];
}

uint8_t cc1101_read_status(uint8_t addr) {
    uint8_t tx_data[2] = { (uint8_t)(addr | 0xC0), 0x00 };
    uint8_t rx_data[2] = { 0 };
    spi_transaction_t t = {
        .length = 16,
        .tx_buffer = tx_data,
        .rx_buffer = rx_data
    };
    spi_device_polling_transmit(spi_handle, &t);
    return rx_data[1];
}

void cc1101_write_burst(uint8_t addr, const uint8_t *data, uint8_t len) {
    uint8_t header = addr | 0x40;
    spi_transaction_t t = {
        .length = 8,
        .tx_data = {header},
        .flags = SPI_TRANS_USE_TXDATA
    };
    spi_device_polling_transmit(spi_handle, &t);
    spi_transaction_t t_data = {
        .length = len * 8,
        .tx_buffer = data
    };
    spi_device_polling_transmit(spi_handle, &t_data);
}

void cc1101_read_burst(uint8_t addr, uint8_t *data, uint8_t len) {
    uint8_t header = addr | 0xC0;
    spi_transaction_t t = {
        .length = 8,
        .tx_data = {header},
        .flags = SPI_TRANS_USE_TXDATA
    };
    spi_device_polling_transmit(spi_handle, &t);
    spi_transaction_t t_data = {
        .length = len * 8,
        .rx_buffer = data
    };
    spi_device_polling_transmit(spi_handle, &t_data);
}

void radio_hal_init(void) {
    rf_rx_semaphore = xSemaphoreCreateBinary();
    gpio_init();
    spi_init();

    cc1101_strobe(CC1101_SRES);
    vTaskDelay(pdMS_TO_TICKS(10));

    uint8_t partnum = cc1101_read_status(CC1101_PARTNUM);
    uint8_t version = cc1101_read_status(CC1101_VERSION);
    ESP_LOGI(TAG, "CC1101 Found - Part: 0x%02X, Version: 0x%02X", partnum, version);

    for (int i = 0; i < sizeof(erp1_config)/sizeof(cc1101_cfg_t); i++) {
        cc1101_write_reg(erp1_config[i].addr, erp1_config[i].val);
    }
    cc1101_write_burst(0x3E, patable_ook, 2);

    gpio_install_isr_service(0);
    gpio_isr_handler_add(PIN_GDO0, cc1101_gdo0_isr, NULL);

    cc1101_strobe(CC1101_SRX);
    ESP_LOGI(TAG, "CC1101 Initialized and in RX Mode");
}

static bool check_lbt(void) {
    uint8_t rssi_dec = cc1101_read_status(0x34); // RSSI
    if (rssi_dec >= 75) return false; 
    return true;
}

void radio_transmit(const uint8_t *data, uint8_t len) {
    is_transmitting = true;
    for(int i=0; i<5; i++) {
        if(check_lbt()) break;
        vTaskDelay(pdMS_TO_TICKS(2 + (esp_random() % 5)));
    }
    for(int sub = 0; sub < 3; sub++) {
        cc1101_strobe(CC1101_SIDLE);
        cc1101_strobe(CC1101_SFTX);
        cc1101_write_burst(0x3F, data, len);
        cc1101_strobe(CC1101_STX);
        int timeout = 50; 
        while((cc1101_read_status(CC1101_MARCSTATE) & 0x1F) != 0x01 && timeout > 0) {
            vTaskDelay(pdMS_TO_TICKS(1));
            timeout--;
        }
        if (sub < 2) {
            vTaskDelay(pdMS_TO_TICKS(10 + (esp_random() % 16)));
        }
    }
    cc1101_strobe(CC1101_SFRX);
    cc1101_strobe(CC1101_SRX);
    is_transmitting = false;
}

#ifndef ESP3_PROTO_H
#define ESP3_PROTO_H

#include <stdint.h>
#include <stdbool.h>

#define ESP3_SYNC_BYTE 0x55

// ESP3 Packet Types
#define ESP3_TYPE_RADIO_ERP1 0x01
#define ESP3_TYPE_RESPONSE   0x02

// Response Codes
#define RET_OK 0x00

typedef struct {
    uint16_t data_len;
    uint8_t opt_len;
    uint8_t packet_type;
    uint8_t *data;
    uint8_t *opt_data;
} esp3_packet_t;

// API
void esp3_init(void);
void esp3_process_byte(uint8_t byte);
void esp3_send_packet(uint8_t type, const uint8_t *data, uint16_t data_len, const uint8_t *opt, uint8_t opt_len);
void esp3_send_response(uint8_t ret_code);

#endif // ESP3_PROTO_H

#include "esp3_proto.h"
#include "radio_hal.h"
#include "driver/usb_serial_jtag.h"
#include <stdlib.h>
#include <string.h>

typedef enum {
    STATE_SYNC, STATE_HEADER, STATE_CRC8H, STATE_DATA, STATE_CRC8D
} esp3_state_t;

static esp3_state_t rx_state = STATE_SYNC;
static uint8_t header_buf[4];
static uint8_t header_idx = 0;
static uint8_t *payload_buf = NULL;
static uint16_t payload_idx = 0;
static esp3_packet_t current_packet;

// EnOcean CRC8
static uint8_t crc8_table[256];
static bool crc8_table_init = false;

static void init_crc8_table(void) {
    for (int i = 0; i < 256; i++) {
        uint8_t crc = i;
        for (int j = 0; j < 8; j++) {
            if (crc & 0x80) crc = (crc << 1) ^ 0x07;
            else crc <<= 1;
        }
        crc8_table[i] = crc;
    }
    crc8_table_init = true;
}

static uint8_t calc_buffer_crc(const uint8_t *buf, uint16_t len) {
    if (!crc8_table_init) init_crc8_table();
    uint8_t crc = 0;
    for (uint16_t i = 0; i < len; i++) {
        crc = crc8_table[crc ^ buf[i]];
    }
    return crc;
}

void esp3_init(void) {
    rx_state = STATE_SYNC;
    if (!crc8_table_init) init_crc8_table();
}

void esp3_send_packet(uint8_t type, const uint8_t *data, uint16_t data_len, const uint8_t *opt, uint8_t opt_len) {
    uint8_t header[4] = { (uint8_t)(data_len >> 8), (uint8_t)(data_len & 0xFF), opt_len, type };
    uint8_t crc8h = calc_buffer_crc(header, 4);

    uint8_t crc8d = 0;
    if (data_len > 0 || opt_len > 0) {
        // Calculate CRC8 over data then opt_data
        if (data_len > 0) {
             for(int i=0; i<data_len; i++) crc8d = crc8_table[crc8d ^ data[i]];
        }
        if (opt_len > 0) {
             for(int i=0; i<opt_len; i++) crc8d = crc8_table[crc8d ^ opt[i]];
        }
    }

    uint8_t sync = ESP3_SYNC_BYTE;
    usb_serial_jtag_write_bytes(&sync, 1, portMAX_DELAY);
    usb_serial_jtag_write_bytes(header, 4, portMAX_DELAY);
    usb_serial_jtag_write_bytes(&crc8h, 1, portMAX_DELAY);
    if (data_len > 0) usb_serial_jtag_write_bytes(data, data_len, portMAX_DELAY);
    if (opt_len > 0) usb_serial_jtag_write_bytes(opt, opt_len, portMAX_DELAY);
    usb_serial_jtag_write_bytes(&crc8d, 1, portMAX_DELAY);
}

void esp3_send_response(uint8_t ret_code) {
    esp3_send_packet(ESP3_TYPE_RESPONSE, &ret_code, 1, NULL, 0);
}

void esp3_process_byte(uint8_t byte) {
    switch (rx_state) {
        case STATE_SYNC:
            if (byte == ESP3_SYNC_BYTE) {
                header_idx = 0;
                rx_state = STATE_HEADER;
            }
            break;
        case STATE_HEADER:
            header_buf[header_idx++] = byte;
            if (header_idx == 4) rx_state = STATE_CRC8H;
            break;
        case STATE_CRC8H:
            if (byte == calc_buffer_crc(header_buf, 4)) {
                current_packet.data_len = (header_buf[0] << 8) | header_buf[1];
                current_packet.opt_len = header_buf[2];
                current_packet.packet_type = header_buf[3];
                uint16_t total_len = current_packet.data_len + current_packet.opt_len;
                if (total_len > 0) {
                    payload_buf = malloc(total_len);
                    if (!payload_buf) { rx_state = STATE_SYNC; return; }
                    payload_idx = 0;
                    rx_state = STATE_DATA;
                } else {
                    rx_state = STATE_CRC8D;
                }
            } else {
                rx_state = STATE_SYNC;
            }
            break;
        case STATE_DATA:
            payload_buf[payload_idx++] = byte;
            if (payload_idx == (current_packet.data_len + current_packet.opt_len)) {
                rx_state = STATE_CRC8D;
            }
            break;
        case STATE_CRC8D:
            {
                uint16_t total_len = current_packet.data_len + current_packet.opt_len;
                uint8_t expected_crc = calc_buffer_crc(payload_buf, total_len);
                if (byte == expected_crc) {
                    current_packet.data = payload_buf;
                    current_packet.opt_data = payload_buf + current_packet.data_len;
                    if (current_packet.packet_type == ESP3_TYPE_RADIO_ERP1) {
                        radio_transmit(current_packet.data, current_packet.data_len);
                        esp3_send_response(RET_OK);
                    }
                }
            }
            if (payload_buf) free(payload_buf);
            payload_buf = NULL;
            rx_state = STATE_SYNC;
            break;
    }
}

#include <stdio.h>
#include <string.h>
#include "freertos/FreeRTOS.h"
#include "freertos/task.h"
#include "driver/usb_serial_jtag.h"
#include "esp_log.h"
#include "esp3_proto.h"
#include "radio_hal.h"

static const char *TAG = "MAIN";

void usb_rx_task(void *pvParameters) {
    uint8_t rx_buf[128];
    while (1) {
        int bytes_read = usb_serial_jtag_read_bytes(rx_buf, sizeof(rx_buf), portMAX_DELAY);
        if (bytes_read > 0) {
            for (int i = 0; i < bytes_read; i++) {
                esp3_process_byte(rx_buf[i]);
            }
        }
    }
}

void rf_rx_task(void *pvParameters) {
    uint8_t fifo_buf[64];
    while (1) {
        if (xSemaphoreTake(rf_rx_semaphore, portMAX_DELAY) == pdTRUE) {
            // Read MARCSTATE to ensure we are still in RX or just finished
            // In ERP1 Packet Mode, CC1101 should have a full packet in FIFO
            uint8_t rxbytes = cc1101_read_status(0x3B) & 0x7F; // RXBYTES

            if (rxbytes > 0 && rxbytes <= 64) {
                cc1101_read_burst(0x3F, fifo_buf, rxbytes);

                // EnOcean usually appends RSSI and LQI if configured
                // For now, let's just send the raw packet as Data
                // and a dummy RSSI as Optional Data
                uint8_t rssi = cc1101_read_status(0x34);
                uint8_t opt_data[1] = { rssi };

                esp3_send_packet(ESP3_TYPE_RADIO_ERP1, fifo_buf, rxbytes, opt_data, 1);
            }

            // Re-arm RX
            cc1101_strobe(0x36); // SIDLE
            cc1101_strobe(0x3A); // SFRX
            cc1101_strobe(0x34); // SRX
        }
    }
}

void app_main(void) {
    // Disable logging to USB CDC to avoid corrupting ESP3 stream
    esp_log_level_set("*", ESP_LOG_NONE);

    // Initialize USB Serial JTAG driver
    usb_serial_jtag_driver_config_t usb_config = {
        .tx_buffer_size = 256,
        .rx_buffer_size = 256,
    };
    usb_serial_jtag_driver_install(&usb_config);

    // Initialize ESP3 parser
    esp3_init();

    // Initialize Radio HAL (SPI, GPIO, CC1101)
    radio_hal_init();

    // Start Tasks
    xTaskCreate(usb_rx_task, "usb_rx", 4096, NULL, 5, NULL);
    xTaskCreate(rf_rx_task, "rf_rx", 4096, NULL, 6, NULL);

    // Main loop does nothing
    while (1) {
        vTaskDelay(pdMS_TO_TICKS(1000));
    }
}

