    rmt_receive_config_t receive_config = {
        .signal_delay_ticks = 200, // Timeout: 200µs ohne Flanke = Ende des Pakets
    };

    rmt_symbol_word_t raw_symbols[256];

    while (1) {
        // Starte RMT Empfang
        ESP_ERROR_CHECK(rmt_receive(rx_channel, raw_symbols, sizeof(raw_symbols), &receive_config));

        // Warte auf Abschluss (in Prod: verwende Callbacks & Queues)
        rmt_rx_done_event_data_t rx_data;
        // ... (Warte-Logik basierend auf FreeRTOS Event/Queue aus dem RMT Callback)

        // Dekodierungs-Logik auf den raw_symbols
        decode_manchester(raw_symbols, num_symbols_received);
    }
}

void decode_manchester(rmt_symbol_word_t* symbols, size_t count) {
    uint8_t buffer[64] = {0};
    int bit_idx = 0;
    int byte_idx = 0;

    // State machine für Manchester (Standard: Flanke Mitte des Bits)
    // IEEE 802.3: High->Low = 0, Low->High = 1
    // (EnOcean nutzt oft G.E. Thomas: High->Low = 1, abhängig von Invertierung im CC1101)

    for (int i = 0; i < count; i++) {
        uint32_t duration_0 = symbols[i].duration_0;
        uint32_t duration_1 = symbols[i].duration_1;

        // Verarbeite Level 0 (duration_0) und Level 1 (duration_1)
        // Unterscheide zwischen PULSE_SHORT und PULSE_LONG.
        // Ein langer Puls bedeutet: Aktuelles Bit ist gleich dem vorherigen Bit.
        // Zwei kurze Pulse bedeuten: Aktuelles Bit wechselt (Flanke in der Mitte).

        /* 
           Implementiere hier eine Shift-Register-Logik.
           Suche im Shift-Register nach der Preamble (0xA5 / 0x5A).
